noncompliant:
// Noncompliant: Unused functions
void unusedFunction() {
  // This function is never called
}

static void unusedStaticFunction() {
  // This static function is never called
}

int main() {
  // Neither unusedFunction nor unusedStaticFunction is called
  return 0;
}

compliant:
// Compliant: All functions are used
void helperFunction() {
  printf("Helper function called\n");
}

int main() {
  helperFunction();  // Function is called
  return 0;
}
